const trigger = $('Report Generate Webhook').first()?.json ?? $('When Executed by Another Workflow').first()?.json ?? $('When clicking \'Execute workflow\'').first()?.json ?? {};
const request = trigger.body ?? trigger.query ?? trigger ?? {};
const settings = $('Load Report Settings').first()?.json ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const toArray = (value) => {
  if (Array.isArray(value)) return value.map(clean).filter(Boolean);
  const text = clean(value);
  return text ? [text] : [];
};
const parseJsonSetting = (value, fallback) => {
  const text = clean(value);
  if (!text) return fallback;
  try {
    return JSON.parse(text);
  } catch (error) {
    throw new Error(`Invalid JSON in global settings: ${error.message}`);
  }
};
const sanitizeName = (value) => clean(value).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '') || 'metabase-report';
const splitTerms = (value) => clean(value).split(/[\n,;]+/).map((entry) => entry.trim()).filter(Boolean);
const dashboards = parseJsonSetting(settings.metabase_report_dashboards_json, []);
const profiles = parseJsonSetting(settings.metabase_report_redaction_profiles_json, []);
if (!dashboards.length) throw new Error('No Metabase dashboards are configured in global_settings.');
const requestedDashboardId = clean(request.dashboard_id);
const dashboard = dashboards.find((candidate) => String(candidate.id) === requestedDashboardId) || dashboards[0];
const reportMode = clean(request.report_mode) || 'redact';
if (!['redact', 'anonymise'].includes(reportMode)) throw new Error(`Unsupported report_mode: ${reportMode}`);
const requestedTabs = toArray(request['tabs[]'] ?? request.tabs);
const resolvedTabs = (requestedTabs.length ? requestedTabs : (dashboard.defaultTabs ?? []).map(String))
  .map((tabId) => (dashboard.tabs ?? []).find((tab) => String(tab.id) === String(tabId)))
  .filter(Boolean);
if (!resolvedTabs.length) throw new Error('At least one valid dashboard tab must be selected.');
const selectedProfileId = clean(request.redaction_profile) || clean(profiles[0]?.id);
const redactionProfile = profiles.find((candidate) => String(candidate.id) === selectedProfileId) || profiles[0] || null;
const extraTerms = splitTerms(request.extra_redaction_terms);
if (reportMode === 'redact' && !redactionProfile && !extraTerms.length) throw new Error('Redact mode requires a profile or extra redact terms.');
const filters = {};
const filterMap = dashboard.filterMap ?? {};
const year = clean(request.year);
const search = clean(request.search);
if (year) filters[clean(filterMap.year) || 'year'] = year;
if (search) filters[clean(filterMap.search) || 'search'] = search;
const anonymisedDashboardId = Number(dashboard.anonymisedDashboardId ?? 0);
const hasDedicatedAnonymisedDashboard = Number.isInteger(anonymisedDashboardId) && anonymisedDashboardId > 0;
const effectiveDashboardId = reportMode === 'anonymise' && hasDedicatedAnonymisedDashboard ? anonymisedDashboardId : Number(dashboard.id);
const effectiveDashboardName = reportMode === 'anonymise' && hasDedicatedAnonymisedDashboard ? `${dashboard.name} (Anonymised)` : dashboard.name;
const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
const baseOutputName = sanitizeName(clean(request.output_name) || `${dashboard.slug || dashboard.name}-${reportMode}-${timestamp}`);
return [{
  json: {
    dashboardId: Number(effectiveDashboardId),
    dashboardName: effectiveDashboardName,
    originalDashboardId: Number(dashboard.id),
    originalDashboardName: dashboard.name,
    reportMode,
    filters,
    outputName: baseOutputName,
    tabs: resolvedTabs,
    snapshotDashcards: Array.isArray(dashboard.snapshotDashcards) ? dashboard.snapshotDashcards : [],
    redactionProfile,
    extraRedactionTerms: extraTerms,
    metabaseBaseUrl: clean(settings.metabase_base_url),
    clubsparkExporterBaseUrl: clean(settings.clubspark_exporter_base_url),
    stirlingBaseUrl: clean(settings.stirling_base_url),
  },
}];

const item = $input.first();
const binary = item.binary?.data;
if (!binary?.data) {
  throw new Error('The exporter did not return a PDF binary payload.');
}
const outputName = String(item.json?.outputName ?? 'metabase-report').replace(/[^A-Za-z0-9._-]+/g, '-');
return [{
  json: {
    ...(item.json ?? {}),
    generatedAt: new Date().toISOString(),
  },
  binary: {
    data: {
      ...binary,
      mimeType: 'application/pdf',
      fileName: `${outputName}.pdf`,
      fileExtension: 'pdf',
    },
  },
}];
